const fs = require("node:fs");
const path = require("node:path");
const { Cookie } = require('./cookie.cjs');
const { RezoMemoryCookieStore } = require('./memory-store.cjs');

class RezoFileCookieStore extends RezoMemoryCookieStore {
  filePath;
  format;
  saveDebounce;
  prettyPrint;
  saveTimer = null;
  saving = false;
  constructor(options) {
    super();
    this.filePath = path.resolve(options.filePath);
    this.format = options.format || (this.filePath.endsWith(".txt") ? "netscape" : "json");
    this.saveDebounce = options.saveDebounce ?? 100;
    this.prettyPrint = options.prettyPrint ?? true;
    this.loadSync();
  }
  putCookie(cookie, callback) {
    if (callback) {
      super.putCookie(cookie, (err) => {
        if (!err)
          this.scheduleSave();
        callback(err);
      });
    } else {
      return super.putCookie(cookie).then(() => {
        this.scheduleSave();
      });
    }
  }
  updateCookie(oldCookie, newCookie, callback) {
    if (callback) {
      super.updateCookie(oldCookie, newCookie, (err) => {
        if (!err)
          this.scheduleSave();
        callback(err);
      });
    } else {
      return super.updateCookie(oldCookie, newCookie).then(() => {
        this.scheduleSave();
      });
    }
  }
  removeCookie(domain, path, key, callback) {
    if (callback) {
      super.removeCookie(domain, path, key, (err) => {
        if (!err)
          this.scheduleSave();
        callback(err);
      });
    } else {
      return super.removeCookie(domain, path, key).then(() => {
        this.scheduleSave();
      });
    }
  }
  removeAllCookies(callback) {
    if (callback) {
      super.removeAllCookies((err) => {
        if (!err)
          this.scheduleSave();
        callback(err);
      });
    } else {
      return super.removeAllCookies().then(() => {
        this.scheduleSave();
      });
    }
  }
  loadSync() {
    if (!fs.existsSync(this.filePath))
      return;
    try {
      const content = fs.readFileSync(this.filePath, "utf-8");
      if (!content.trim())
        return;
      if (this.format === "json") {
        this.loadFromJson(content);
      } else {
        this.loadFromNetscape(content);
      }
    } catch {}
  }
  saveSync() {
    this.clearSaveTimer();
    this.saving = true;
    try {
      const dir = path.dirname(this.filePath);
      if (!fs.existsSync(dir)) {
        fs.mkdirSync(dir, { recursive: true });
      }
      const content = this.format === "json" ? this.serializeJson() : this.serializeNetscape();
      const tmpPath = this.filePath + ".tmp";
      fs.writeFileSync(tmpPath, content, "utf-8");
      fs.renameSync(tmpPath, this.filePath);
    } finally {
      this.saving = false;
    }
  }
  getFilePath() {
    return this.filePath;
  }
  getFormat() {
    return this.format;
  }
  flush() {
    if (this.saveTimer) {
      this.saveSync();
    }
  }
  close() {
    this.flush();
    this.clearSaveTimer();
  }
  static fromFile(filePath, options) {
    return new RezoFileCookieStore({ ...options, filePath });
  }
  getAllCookiesFromIdx() {
    const result = [];
    for (const paths of Object.values(this.idx)) {
      for (const keys of Object.values(paths)) {
        for (const cookie of Object.values(keys)) {
          result.push(cookie);
        }
      }
    }
    return result;
  }
  serializeJson() {
    const cookies = this.getAllCookiesFromIdx();
    const data = {
      version: 1,
      savedAt: new Date().toISOString(),
      cookies: cookies.map((c) => c.toJSON())
    };
    return this.prettyPrint ? JSON.stringify(data, null, 2) : JSON.stringify(data);
  }
  serializeNetscape() {
    const cookies = this.getAllCookiesFromIdx();
    let out = `# Netscape HTTP Cookie File
`;
    out += `# Generated by Rezo HTTP client

`;
    for (const cookie of cookies) {
      out += cookie.toNetscapeFormat() + `
`;
    }
    return out;
  }
  loadFromJson(content) {
    const data = JSON.parse(content);
    const rawCookies = Array.isArray(data) ? data : data.cookies || [];
    for (const raw of rawCookies) {
      try {
        const parsed = Cookie.fromJSON(raw);
        if (parsed) {
          const cookie = new Cookie(parsed);
          if (cookie.key && cookie.domain) {
            if (!this.idx[cookie.domain])
              this.idx[cookie.domain] = {};
            if (!this.idx[cookie.domain][cookie.path || "/"])
              this.idx[cookie.domain][cookie.path || "/"] = {};
            this.idx[cookie.domain][cookie.path || "/"][cookie.key] = cookie;
          }
        }
      } catch {}
    }
  }
  loadFromNetscape(content) {
    const lines = content.split(`
`).filter((l) => l.trim() && !l.startsWith("#"));
    for (const line of lines) {
      try {
        const parts = line.split("\t");
        if (parts.length < 7)
          continue;
        const [domain, , cookiePath, secureStr, expiresStr, name, value] = parts;
        let expires;
        if (expiresStr && expiresStr !== "0") {
          expires = new Date(parseInt(expiresStr, 10) * 1000);
        }
        const cookie = new Cookie({
          domain,
          path: cookiePath,
          secure: secureStr.toUpperCase() === "TRUE",
          expires,
          key: name,
          value
        });
        if (cookie.key && cookie.domain) {
          if (!this.idx[cookie.domain])
            this.idx[cookie.domain] = {};
          if (!this.idx[cookie.domain][cookie.path || "/"])
            this.idx[cookie.domain][cookie.path || "/"] = {};
          this.idx[cookie.domain][cookie.path || "/"][cookie.key] = cookie;
        }
      } catch {}
    }
  }
  scheduleSave() {
    if (this.saving)
      return;
    if (this.saveDebounce <= 0) {
      this.saveSync();
      return;
    }
    if (this.saveTimer)
      return;
    this.saveTimer = setTimeout(() => {
      this.saveTimer = null;
      this.saveSync();
    }, this.saveDebounce);
  }
  clearSaveTimer() {
    if (this.saveTimer) {
      clearTimeout(this.saveTimer);
      this.saveTimer = null;
    }
  }
}

exports.RezoFileCookieStore = RezoFileCookieStore;